public class Main {
    static int[] parent;

    static void init(int n) {
        parent = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i; // everyone starts as their own parent -- own separate set
        }
    }

    static int find(int x) {
        if (parent[x] == x) {
            return x; // x is the root of its set
        }
        return find(parent[x]);
    }

    static void union(int a, int b) {
        int rootA = find(a);
        int rootB = find(b);
        if (rootA != rootB) {
            parent[rootA] = rootB;
        }
    }

    public static void main(String[] args) {
        init(5);
        union(0, 1);
        union(1, 2);

        System.out.println(find(0) == find(2));
        System.out.println(find(0) == find(3));
    }
}

